<?php

namespace App\View;

/**
 * Feather-style SVG icon library — same set as the DFCOMMERCE admin layout
 * so the visual identity matches across both apps.
 */
class Icons
{
    public static function svg(string $name, int $size = 18): string
    {
        $library = self::library();
        if (! isset($library[$name])) {
            $name = 'box';
        }
        return str_replace(['{S}'], [(string) $size], $library[$name]);
    }

